CREATE TABLE tournament (id UUID PRIMARY KEY, tournament_date DATE NOT NULL UNIQUE, status VARCHAR(20) NOT NULL, current_round INTEGER NOT NULL, winner_meme_id UUID, starts_at TIMESTAMP WITH TIME ZONE NOT NULL, completed_at TIMESTAMP WITH TIME ZONE, created_at TIMESTAMP WITH TIME ZONE NOT NULL, updated_at TIMESTAMP WITH TIME ZONE NOT NULL, CONSTRAINT fk_tournament_winner FOREIGN KEY(winner_meme_id) REFERENCES meme(id), CONSTRAINT chk_tournament_status CHECK(status IN ('SCHEDULED','ACTIVE','COMPLETED','CANCELLED')));
CREATE TABLE tournament_entry (id UUID PRIMARY KEY, tournament_id UUID NOT NULL, meme_id UUID NOT NULL, seed INTEGER NOT NULL, eliminated_round INTEGER, final_position INTEGER, created_at TIMESTAMP WITH TIME ZONE NOT NULL, CONSTRAINT fk_tournament_entry_tournament FOREIGN KEY(tournament_id) REFERENCES tournament(id) ON DELETE CASCADE, CONSTRAINT fk_tournament_entry_meme FOREIGN KEY(meme_id) REFERENCES meme(id), CONSTRAINT uk_tournament_entry_meme UNIQUE(tournament_id,meme_id), CONSTRAINT uk_tournament_entry_seed UNIQUE(tournament_id,seed));
CREATE INDEX idx_tournament_entry_tournament ON tournament_entry(tournament_id); CREATE INDEX idx_tournament_entry_meme ON tournament_entry(meme_id);
CREATE TABLE tournament_match (id UUID PRIMARY KEY, tournament_id UUID NOT NULL, round_number INTEGER NOT NULL, match_number INTEGER NOT NULL, left_meme_id UUID, right_meme_id UUID, winner_meme_id UUID, left_votes BIGINT NOT NULL DEFAULT 0, right_votes BIGINT NOT NULL DEFAULT 0, status VARCHAR(20) NOT NULL, starts_at TIMESTAMP WITH TIME ZONE NOT NULL, ends_at TIMESTAMP WITH TIME ZONE NOT NULL, completed_at TIMESTAMP WITH TIME ZONE, created_at TIMESTAMP WITH TIME ZONE NOT NULL, updated_at TIMESTAMP WITH TIME ZONE NOT NULL, CONSTRAINT fk_tournament_match_tournament FOREIGN KEY(tournament_id) REFERENCES tournament(id) ON DELETE CASCADE, CONSTRAINT fk_tournament_match_left FOREIGN KEY(left_meme_id) REFERENCES meme(id), CONSTRAINT fk_tournament_match_right FOREIGN KEY(right_meme_id) REFERENCES meme(id), CONSTRAINT fk_tournament_match_winner FOREIGN KEY(winner_meme_id) REFERENCES meme(id), CONSTRAINT uk_tournament_match_round UNIQUE(tournament_id,round_number,match_number), CONSTRAINT chk_tournament_match_status CHECK(status IN ('PENDING','ACTIVE','COMPLETED','BYE')));
CREATE INDEX idx_tournament_match_tournament_round ON tournament_match(tournament_id,round_number); CREATE INDEX idx_tournament_match_status_ends ON tournament_match(status,ends_at);
CREATE TABLE tournament_vote (id UUID PRIMARY KEY, match_id UUID NOT NULL, user_id UUID NOT NULL, selected_meme_id UUID NOT NULL, created_at TIMESTAMP WITH TIME ZONE NOT NULL, CONSTRAINT fk_tournament_vote_match FOREIGN KEY(match_id) REFERENCES tournament_match(id) ON DELETE CASCADE, CONSTRAINT fk_tournament_vote_user FOREIGN KEY(user_id) REFERENCES user_profile(id), CONSTRAINT fk_tournament_vote_meme FOREIGN KEY(selected_meme_id) REFERENCES meme(id), CONSTRAINT uk_tournament_vote_match_user UNIQUE(match_id,user_id));
CREATE INDEX idx_tournament_vote_match ON tournament_vote(match_id); CREATE INDEX idx_tournament_vote_user ON tournament_vote(user_id);
CREATE TABLE meme_tournament_stats (meme_id UUID PRIMARY KEY, participations BIGINT NOT NULL DEFAULT 0, finals BIGINT NOT NULL DEFAULT 0, wins BIGINT NOT NULL DEFAULT 0, updated_at TIMESTAMP WITH TIME ZONE NOT NULL, CONSTRAINT fk_meme_tournament_stats_meme FOREIGN KEY(meme_id) REFERENCES meme(id));
